from dataclasses import dataclass
from typing import List

@dataclass
class Product:
    name: str
    price: float

def build_form() -> List[Product]:
    products = [
        Product(name='sylius.form.product.name', price=0.0),
        Product(name='sylius.form.product.price', price=0.0)
    ]
    return products

def set_default_options() -> dict:
    return {
        'data_class': Product
    }

def get_name() -> str:
    return 'product_type'
